import hashlib
import secrets

# Simulated Authorization Server
class AuthorizationServer:
    def __init__(self):
        self.authorization_codes = {}
        self.tokens = {}

    def generate_auth_code(self, client_id, redirect_uri, user_id):
        code = secrets.token_urlsafe(32)
        self.authorization_codes[code] = {
            'client_id': client_id,
            'redirect_uri': redirect_uri,
            'user_id': user_id
        }
        return code

    def exchange_code_for_token(self, auth_code, client_id, client_secret):
        if auth_code in self.authorization_codes:
            code_data = self.authorization_codes[auth_code]
            if code_data['client_id'] == client_id:
                access_token = secrets.token_urlsafe(32)
                self.tokens[access_token] = code_data['user_id']
                return {'access_token': access_token, 'token_type': 'Bearer'}
        return None

# Usage
auth_server = AuthorizationServer()
auth_code = auth_server.generate_auth_code('cloud_app', 'https://app.com/callback', 'user123')
print(f"Auth Code: {auth_code}")
token_response = auth_server.exchange_code_for_token(auth_code, 'cloud_app', 'secret')
print(f"Token Response: {token_response}")
